module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                   clk,
    input  logic                   rst_n,
    input  logic                   enable,
    input  logic                   clear,
    input  logic [STEP_WIDTH-1:0]  step,
    output logic [COUNT_WIDTH-1:0] count,
    output logic                   wrapped,
    output logic                   valid
);

    // Architectural state variables mirrored from function_model.state_variables.
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    // FM_CLEAR/FM_UPDATE/FM_IDLE commit values; consumed by the sequential state update.
    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    // Extended adder for overflow detection and modulo truncation.
    logic [COUNT_WIDTH:0] step_ext;
    logic [COUNT_WIDTH:0] sum_ext;

    assign step_ext = {{(COUNT_WIDTH-STEP_WIDTH+1){1'b0}}, step};
    assign sum_ext  = {1'b0, count_q} + step_ext;

    // Combinational transaction decode with clear priority over enable.
    // This drives commit values used at the accepting clock edge (latency=1 contract).
    always @(*) begin
        out_count   = count_q;
        out_wrapped = 1'b0;
        out_valid   = 1'b0;

        if (clear == 1'b1) begin
            // FM_CLEAR: clear wins even when enable is also high.
            out_count   = {COUNT_WIDTH{1'b0}};
            out_wrapped = 1'b0;
            out_valid   = 1'b0;
        end else if (enable == 1'b1) begin
            // FM_UPDATE: modulo increment and one-cycle pulses.
            out_count   = sum_ext[COUNT_WIDTH-1:0];
            out_wrapped = sum_ext[COUNT_WIDTH];
            out_valid   = 1'b1;
        end else begin
            // FM_IDLE: hold count state, pulse outputs deasserted.
            out_count   = count_q;
            out_wrapped = 1'b0;
            out_valid   = 1'b0;
        end
    end

    // State commit. Async assert, sync release reset behavior per SSOT.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else begin
            count_q   <= out_count;
            wrapped_q <= out_wrapped;
            valid_q   <= out_valid;
        end
    end

    // Architectural outputs are the registered state observables.
    assign count   = count_q;
    assign wrapped = wrapped_q;
    assign valid   = valid_q;

endmodule

